-- Base MySQL gerada a partir do arquivo: Relatorios 06-2026 - Bruto(1)
-- Total de lançamentos: 308 | Total de despesas: R$ 179.099,49
CREATE DATABASE IF NOT EXISTS cetel_financeiro CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE cetel_financeiro;
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS=0;
DROP VIEW IF EXISTS vw_gastos_por_fornecedor;
DROP VIEW IF EXISTS vw_gastos_por_categoria;
DROP VIEW IF EXISTS vw_gastos_por_cidade;
DROP TABLE IF EXISTS lancamentos;
DROP TABLE IF EXISTS fornecedores;
DROP TABLE IF EXISTS categorias;
DROP TABLE IF EXISTS usuarios;
SET FOREIGN_KEY_CHECKS=1;

CREATE TABLE categorias (
  id INT AUTO_INCREMENT PRIMARY KEY,
  nome VARCHAR(255) NOT NULL UNIQUE,
  cidade_inferida VARCHAR(120) NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE fornecedores (
  id INT AUTO_INCREMENT PRIMARY KEY,
  nome VARCHAR(255) NOT NULL UNIQUE,
  tipo_doc VARCHAR(80) NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE usuarios (
  id INT AUTO_INCREMENT PRIMARY KEY,
  nome VARCHAR(120) NOT NULL UNIQUE,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE lancamentos (
  id INT AUTO_INCREMENT PRIMARY KEY,
  lancamento DATE NULL,
  data_documento DATE NULL,
  recibo VARCHAR(120) NULL,
  baixa VARCHAR(50) NULL,
  data_credito DATE NULL,
  exec_baixa DATETIME NULL,
  numero VARCHAR(80) NULL,
  nosso_numero VARCHAR(80) NULL,
  historico VARCHAR(120) NULL,
  categoria_id INT NOT NULL,
  fornecedor_id INT NOT NULL,
  usuario_id INT NOT NULL,
  banco VARCHAR(120) NULL,
  valor DECIMAL(12,2) NOT NULL DEFAULT 0.00,
  cidade_inferida VARCHAR(120) NULL,
  origem_arquivo VARCHAR(255) NULL,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  CONSTRAINT fk_lancamentos_categoria FOREIGN KEY (categoria_id) REFERENCES categorias(id),
  CONSTRAINT fk_lancamentos_fornecedor FOREIGN KEY (fornecedor_id) REFERENCES fornecedores(id),
  CONSTRAINT fk_lancamentos_usuario FOREIGN KEY (usuario_id) REFERENCES usuarios(id),
  INDEX idx_lancamentos_data (lancamento),
  INDEX idx_lancamentos_categoria (categoria_id),
  INDEX idx_lancamentos_fornecedor (fornecedor_id),
  INDEX idx_lancamentos_usuario (usuario_id),
  INDEX idx_lancamentos_cidade (cidade_inferida)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;





CREATE OR REPLACE VIEW vw_gastos_por_fornecedor AS
SELECT f.nome AS fornecedor, COUNT(*) AS qtd_lancamentos, SUM(l.valor) AS total
FROM lancamentos l
JOIN fornecedores f ON f.id = l.fornecedor_id
GROUP BY f.id, f.nome
ORDER BY total DESC;

CREATE OR REPLACE VIEW vw_gastos_por_categoria AS
SELECT c.nome AS categoria, c.cidade_inferida, COUNT(*) AS qtd_lancamentos, SUM(l.valor) AS total
FROM lancamentos l
JOIN categorias c ON c.id = l.categoria_id
GROUP BY c.id, c.nome, c.cidade_inferida
ORDER BY total DESC;

CREATE OR REPLACE VIEW vw_gastos_por_cidade AS
SELECT COALESCE(NULLIF(l.cidade_inferida, ''), 'SEM CIDADE') AS cidade, COUNT(*) AS qtd_lancamentos, SUM(l.valor) AS total
FROM lancamentos l
GROUP BY COALESCE(NULLIF(l.cidade_inferida, ''), 'SEM CIDADE')
ORDER BY total DESC;
